**Best fix with reflection to mock getClass().getSimpleName():**

```java
package com.google.gson;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Proxy;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;

class JsonElementTest {

  @Test
  void testGetAsDouble_throwsUnsupportedOperationException() throws Exception {
    JsonElement jsonElement = new JsonElement() {
      @Override
      public JsonElement deepCopy() {
        return this;
      }
      @Override
      public Class<?> getClass() {
        return new Class<Object>() {
          @Override
          public String getSimpleName() {
            return "JsonElement$1";
          }
        };
      }
    };

    UnsupportedOperationException exception = assertThrows(UnsupportedOperationException.class, jsonElement::getAsDouble);
    assertEquals("JsonElement$1", exception.getMessage());
  }
}
```

---

**Note**: Since `getClass()` is final in `Object`, it cannot be overridden, so the above won't compile.

